import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate, Link, useLocation } from 'react-router-dom';
import './AdminNavigation.css';

const AdminNavigation = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const isActive = (path) => location.pathname === path;

  return (
    <>
      <div className="admin-header">
        <div className="admin-header-left">
          <button 
            className="sidebar-toggle"
            onClick={() => setSidebarOpen(!sidebarOpen)}
          >
            ☰
          </button>
          <Link to="/admin" className="admin-logo">⚡ Sun Electronics Admin</Link>
        </div>
        <div className="admin-header-right">
          <span className="admin-user">👤 {user?.name}</span>
          <button onClick={handleLogout} className="logout-btn">Logout</button>
        </div>
      </div>

      <div className={`admin-sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
        <nav className="admin-nav">
          <Link 
            to="/admin" 
            className={`admin-nav-link ${isActive('/admin') ? 'active' : ''}`}
          >
            📊 Dashboard
          </Link>
          <Link 
            to="/admin/products" 
            className={`admin-nav-link ${isActive('/admin/products') ? 'active' : ''}`}
          >
            📦 Products Management
          </Link>
          <Link 
            to="/admin/orders" 
            className={`admin-nav-link ${isActive('/admin/orders') ? 'active' : ''}`}
          >
            🛒 Orders Management
          </Link>
          <Link 
            to="/admin/users" 
            className={`admin-nav-link ${isActive('/admin/users') ? 'active' : ''}`}
          >
            👥 Users Management
          </Link>
          <Link 
            to="/admin/analytics" 
            className={`admin-nav-link ${isActive('/admin/analytics') ? 'active' : ''}`}
          >
            📈 Analytics
          </Link>
          <hr style={{margin: '1rem 0', opacity: 0.3}} />
          <button 
            onClick={handleLogout}
            className="admin-nav-link logout-link"
          >
            🚪 Logout
          </button>
        </nav>
      </div>
    </>
  );
};

export default AdminNavigation;
